auto uni = [&](int a, int b){
    a = find(a); b = find(b);
    if (a == b) return false;
    if (rk[a] < rk[b]) swap(a, b);
    par[b] = a;
    if (rk[a] == rk[b]) rk[a]++;
    return true;
};

