void update(int node, int l, int r, int pos, long long val) {
    if (l == r) { seg[node] = val; return; }
    int m = (l + r) / 2;
    if (pos <= m) update(node*2, l, m, pos, val);
    else update(node*2+1, m+1, r, pos, val);
    seg[node] = seg[node*2] + seg[node*2+1];
}

